const results = [];
const items = $input.all();

const promises = items.map(async (item) => {
  const data = item.json;
  const title = data.title || '';
  const content = data.cleaned_content || '';
  const textToEmbed = title ? `Title: ${title}\n\nContent: ${content}` : `Content: ${content}`;

  try {
    const response = await fetch('https://ollama.com/api/embeddings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${process.env.OLLAMA_API_KEY}`
      },
      body: JSON.stringify({
        model: 'nomic-embed-text',
        prompt: textToEmbed
      })
    });

    if (response.ok) {
      const resJson = await response.json();
      if (resJson.embedding) {
        return {
          json: {
            source_table: data.source_table,
            id: data.id,
            embedding: `[${resJson.embedding.join(',')}]`
          }
        };
      }
    }
  } catch (err) {
    console.error(`Failed to generate embedding for ${data.source_table} (${data.id}):`, err.message);
  }
  return null;
});

const resolved = await Promise.all(promises);
return resolved.filter(x => x !== null);
